// Verify the shared token (disabled while EXPECTED_TOKEN is empty) and
// compute the 7-day aggregate request body for Google Fit.
const input = $input.first().json;
const headers = input.headers || {};
const received = headers['x-fitness-token'] || '';

// Set EXPECTED_TOKEN to a non-empty value to enforce. Empty = disabled (first test pass).
const EXPECTED_TOKEN = '';
if (EXPECTED_TOKEN && received !== EXPECTED_TOKEN) {
  throw new Error('Unauthorized: bad or missing x-fitness-token header');
}

const days = 7;
const end = DateTime.now();
const start = end.minus({ days });
const endTimeMillis = Math.round(end.toMillis());
const startTimeMillis = Math.round(start.toMillis());

const aggregateBody = {
  aggregateBy: [
    { dataTypeName: 'com.google.step_count.delta' },
    { dataTypeName: 'com.google.calories.expended' },
    { dataTypeName: 'com.google.distance.delta' },
    { dataTypeName: 'com.google.heart_rate.bpm' },
  ],
  bucketByTime: { durationMillis: 86400000 },
  startTimeMillis,
  endTimeMillis,
};

return [{ json: { days, startTimeMillis, endTimeMillis, aggregateBody, tokenOk: true } }];

// Merge the three Google calls into one friendly payload. Each HTTP node used
// fullResponse + neverError, so every call yields { statusCode, headers, body }
// regardless of success — we never throw, we report.
function extractError(body) {
  if (body == null) return 'No response body';
  if (typeof body === 'string') return body.slice(0, 300);
  if (body.error && body.error.message) return body.error.message;
  if (body.error_description) return body.error_description;
  if (typeof body.error === 'string') return body.error;
  return JSON.stringify(body).slice(0, 300);
}

function pick(nodeName) {
  try {
    const j = $(nodeName).first().json;
    const status = typeof j.statusCode === 'number' ? j.statusCode : null;
    const body = j.body !== undefined ? j.body : j;
    const ok = typeof status === 'number' && status >= 200 && status < 300;
    return { ok, status, body };
  } catch (e) {
    return { ok: false, status: null, body: null, error: e.message };
  }
}

const prep = $('Prep').first().json;
const userinfo = pick('Userinfo');
const dataSources = pick('Fit Data Sources');
const aggregate = pick('Fit Aggregate');

let auth;
if (userinfo.ok) {
  const u = userinfo.body || {};
  auth = { ok: true, user: { email: u.email || null, name: u.name || null, picture: u.picture || null } };
} else {
  auth = { ok: false, status: userinfo.status, error: extractError(userinfo.body) };
}

let totalSteps = 0;
let totalCalories = 0;
let totalDistanceMeters = 0;
let hrSum = 0;
let hrCount = 0;

const buckets = aggregate.ok && aggregate.body ? (aggregate.body.bucket || []) : [];
for (const bucket of buckets) {
  for (const ds of (bucket.dataset || [])) {
    for (const point of (ds.point || [])) {
      const type = point.dataTypeName || '';
      const v = (point.value && point.value[0]) || {};
      if (type.indexOf('step_count') !== -1) totalSteps += v.intVal || 0;
      else if (type.indexOf('calories') !== -1) totalCalories += v.fpVal || 0;
      else if (type.indexOf('distance') !== -1) totalDistanceMeters += v.fpVal || 0;
      else if (type.indexOf('heart_rate') !== -1 && v.fpVal != null) { hrSum += v.fpVal; hrCount += 1; }
    }
  }
}

const summary = {
  days: prep.days,
  totalSteps,
  totalCalories: Math.round(totalCalories * 10) / 10,
  totalDistanceMeters: Math.round(totalDistanceMeters),
  avgHeartRateBpm: hrCount ? Math.round(hrSum / hrCount) : null,
};

const dsList = dataSources.ok && dataSources.body ? (dataSources.body.dataSource || []) : [];

return [{
  json: {
    ok: true,
    generatedAt: new Date().toISOString(),
    window: { startTimeMillis: prep.startTimeMillis, endTimeMillis: prep.endTimeMillis, days: prep.days },
    auth,
    summary,
    sections: {
      userinfo: {
        ok: userinfo.ok,
        status: userinfo.status,
        error: userinfo.ok ? null : extractError(userinfo.body),
      },
      dataSources: {
        ok: dataSources.ok,
        status: dataSources.status,
        count: dsList.length,
        sample: dsList.slice(0, 5).map((d) => d.dataStreamId || d.dataStreamName || null),
        error: dataSources.ok ? null : extractError(dataSources.body),
      },
      aggregate: {
        ok: aggregate.ok,
        status: aggregate.status,
        buckets: buckets.length,
        error: aggregate.ok ? null : extractError(aggregate.body),
      },
    },
  },
}];
